record.field:
.query-alert {
    font-family: Helvetica, Arial, sans-serif;
    font-size: 12px;
    color: #24292f;
}

.query-alert__logo-wrap {
    margin: 0 0 16px;
}

.query-alert__logo {
    display: block;
    max-width: 180px;
    max-height: 56px;
    height: auto;
}

.query-alert__meta {
    margin: 0 0 12px;
}

.query-alert__table {
    border-collapse: collapse;
    font-family: inherit;
    font-size: inherit;
}

.query-alert__header {
    text-align: left;
    padding: 5px;
    border: 1px solid #d0d7de;
    background: #f6f8fa;
}

.query-alert__cell {
    padding: 5px;
    border: 1px solid #d0d7de;
    vertical-align: top;
}

body { font-family: Arial, sans-serif; font-size: 12px; color: #333; }
table { border-collapse: separate; border-spacing: 0; width: 100%; margin-top: 8px; font-size: 12px; }
th { background-color: #e8e8e8; border-top: 1px solid #ddd; border-bottom: 1px solid #ddd; padding: 8px; text-align: left; }
td { border-bottom: 1px solid #ddd; padding: 12px; }
